@startuml

package "businessRules" {
  package "Entity" {
    class User {
      email: string
      roles: array
      password: string
      firstname: string
      lastname: string
    }

    class Post {
      title: string
      description: string
      createdAt: DateTimeInterface
    }

    class Picture {
      name: string
      url: string
    }

    User "One" *-- "Many" Post : To
    Post "One" *-- "Many" Picture : To
  }
}

@enduml
